mapper.select:
SELECT am.*, u.userName AS memberName
FROM activitymember am LEFT JOIN user u ON am.memberID = u.userID
WHERE am.activityID = #{activityID} AND am.memberID = #{memberID}

mapper.update:
UPDATE activitymember
SET confirmAttendStatus = #{confirmAttendStatus},
    confirmTime = NOW()
WHERE activityID = #{activityID}
  AND memberID = #{memberID}
